function ErrorDisplay({ error, code }: { error: Error; code?: string }) {
  const [showDetails, setShowDetails] = useState(false);
  return (
    <div className="error-card">
      <h2>Something went wrong</h2>
      <p>Please try again or contact support.</p>
      <button onClick={() => setShowDetails(!showDetails)}>
        {showDetails ? 'Hide' : 'Show'} details
      </button>
      {showDetails && (
        <pre className="text-xs">
          {code && `Code: ${code}\n`}
          {error.message}
        </pre>
      )}
    </div>
  );
}

import { useTranslation } from 'react-i18next';
import { useEffect } from 'react';

import i18n from './i18n';

async function loadRouteTranslations(locale: string, namespace: string) {
  if (i18n.hasResourceBundle(locale, namespace)) return;
  const data = await import(`./locales/${locale}/${namespace}.json`);
  i18n.addResourceBundle(locale, namespace, data.default);
}

function Dashboard() {
  useEffect(() => {
    loadRouteTranslations(i18n.language, 'dashboard');
  }, []);
  const { t } = useTranslation('dashboard');
  return <h1>{t('title')}</h1>;
}

