function composeProviders(...providers: React.FC<{ children: React.ReactNode }>[]) {
  return function Composed({ children }: { children: React.ReactNode }) {
    return providers.reduceRight((acc, Provider) => <Provider>{acc}</Provider>, children);
  };
}

